 38→    const parsed = new URL(url);
 39→    const value =
 40→      `${parsed.hostname.replace(/^www\./, "")}${parsed.pathname}`.replace(
 41→        /\/$/,
 42→        "",
 43→      );
 44→    return value.length > 46 ? `${value.slice(0, 43)}...` : value;
 45→  } catch {
