 54→
 55→  const totalSeconds = Math.floor(ms / 1000);
 56→  const seconds = totalSeconds % 60;
 57→  const minutes = Math.floor(totalSeconds / 60) % 60;
 58→  const hours = Math.floor(totalSeconds / 3600);
 59→
 60→  if (hours > 0) {
 61→    return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
 62→  }
 63→
 64→  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
