              </section>
            ) : null}

            {jobError ? (
              <div className="rounded-2xl border border-red-300/40 bg-red-100/60 px-4 py-3 text-sm text-red-900">
                {jobError.message}
              </div>
            ) : job ? (
              <FormatWorkspace
                activeStage={activeStage}
                elapsedTime={elapsedTime}
                job={job}
                view={view}
                onViewChange={setView}
              />
            ) : null}
          </div>
        </CardContent>
      </Card>
    </div>
  );
